1	import type { AssetModel, AssetInstance } from "@prisma/client";
2	
3	type Role = "EMPLOYEE" | "MANAGER" | "IT_ADMIN" | "EXECUTIVE";
4	
5	/**
6	 * Sanitize an AssetModel based on role (§5.2).
7	 * - EMPLOYEE/MANAGER: strip purchasePrice, supplier
8	 * - IT_ADMIN: full access
9	 * - EXECUTIVE: strip supplier, purchasePrice only in aggregate
10	 */
11	export function sanitizeAssetModel(
12	  model: AssetModel,
13	  role: Role
14	): Record<string, unknown> {
15	  const base: Record<string, unknown> = {
16	    id: model.id,
17	    category: model.category,
18	    brandName: model.brandName,
19	    modelName: model.modelName,
20	    specs: model.specs,
21	    warrantyMonths: model.warrantyMonths,
22	    status: model.status,
23	  };
24	
25	  if (role === "IT_ADMIN") {
26	    return {
27	      ...base,
28	      purchasePrice: model.purchasePrice,
29	      supplier: model.supplier,
30	    };
31	  }
32	
33	  if (role === "EXECUTIVE") {
34	    // EXECUTIVE: don't return purchasePrice per-item, only aggregate
35	    return {
36	      ...base,
37	      // no purchasePrice, no supplier, no sn
38	    };
39	  }
40	
41	  // EMPLOYEE / MANAGER: strip price and supplier
42	  return base;
43	}
44	
45	/**
46	 * Sanitize an AssetInstance based on role (§5.2).
47	 * - EMPLOYEE/MANAGER: strip purchasePrice, supplier, sn
48	 *   - MANAGER can see own department's assets
49	 *   - EMPLOYEE can only see their own
50	 * - IT_ADMIN: full access
51	 * - EXECUTIVE: strip supplier, sn; only aggregate data (not individual)
52	 */
53	export function sanitizeAssetInstance(
54	  instance: AssetInstance & { model?: AssetModel },
55	  role: Role
56	): Record<string, unknown> {
57	  const base: Record<string, unknown> = {
58	    id: instance.id,
59	    status: instance.status,
60	    holderId: instance.holderId,
61	    deptId: instance.deptId,
62	    purchaseDate: instance.purchaseDate,
63	    warrantyExpiry: instance.warrantyExpiry,
64	    createdAt: instance.createdAt,
65	    updatedAt: instance.updatedAt,
66	  };
67	
68	  if (instance.model) {
69	    Object.assign(base, { model: sanitizeAssetModel(instance.model, role) });
70	  }
71	
72	  if (role === "IT_ADMIN") {
73	    return {
74	      ...base,
75	      sn: instance.sn,
76	    };
77	  }
78	
79	  // EMPLOYEE/MANAGER/EXECUTIVE: strip sn
80	  return base;
81	}
