1	"use client";
2	
3	import React, { createContext, useContext, useState, useCallback, useEffect } from "react";
4	import { setToken, clearToken, apiFetch } from "./api-client";
5	
6	export type UserRole = "EMPLOYEE" | "MANAGER" | "IT_ADMIN" | "EXECUTIVE";
7	
8	export interface User {
9	  id: string;
10	  name: string;
11	  email: string;
12	  role: UserRole;
13	  avatar?: string;
14	  department: string;
15	  departmentId: string;
16	}
17	
18	interface AuthContextType {
19	  user: User;
20	  token: string | null;
21	  loading: boolean;
22	  login: (email: string, password: string) => Promise<void>;
23	  logout: () => void;
24	  setRole: (role: UserRole) => void;
25	  unreadNotifications: number;
26	  setUnreadNotifications: (n: number) => void;
27	}
28	
29	const defaultUser: User = {
30	  id: "user-001",
31	  name: "张明",
32	  email: "zhangming@company.com",
33	  role: "EMPLOYEE",
34	  department: "研发部",
35	  departmentId: "dept-dev",
36	};
37	
38	const roleNames: Record<UserRole, string> = {
39	  EMPLOYEE: "张明",
40	  MANAGER: "李主管",
41	  IT_ADMIN: "王工",
42	  EXECUTIVE: "赵总",
43	};
44	
45	const AuthContext = createContext<AuthContextType>({
46	  user: defaultUser,
47	  token: null,
48	  loading: false,
49	  login: async () => {},
50	  logout: () => {},
51	  setRole: () => {},
52	  unreadNotifications: 3,
53	  setUnreadNotifications: () => {},
54	});
55	
56	export function AuthProvider({ children }: { children: React.ReactNode }) {
57	  const [user, setUser] = useState<User>(defaultUser);
58	  const [token, setTokenState] = useState<string | null>(null);
59	  const [loading, setLoading] = useState(true);
60	  const [unreadNotifications, setUnreadNotifications] = useState(3);
61	
62	  useEffect(() => {
63	    const stored = typeof window !== "undefined" ? localStorage.getItem("auth-token") : null;
64	    if (stored) {
65	      setTokenState(stored);
66	      apiFetch<{ user: User }>("/api/auth/session")
67	        .then((data) => setUser(data.user))
68	        .catch(() => { clearToken(); setTokenState(null); })
69	        .finally(() => setLoading(false));
70	    } else {
71	      setLoading(false);
72	    }
73	  }, []);
74	
75	  const login = useCallback(async (email: string, password: string) => {
76	    const data = await apiFetch<{ user: User; token: string }>("/api/auth/login", {
77	      method: "POST",
78	      body: JSON.stringify({ email, password }),
79	    });
80	    setToken(data.token);
81	    setTokenState(data.token);
82	    setUser(data.user);
83	  }, []);
84	
85	  const logout = useCallback(() => {
86	    clearToken();
87	    setTokenState(null);
88	    setUser(defaultUser);
89	  }, []);
90	
91	  const setRole = useCallback((role: UserRole) => {
92	    setUser((prev) => ({ ...prev, role, name: roleNames[role] }));
93	  }, []);
94	
95	  return (
96	    <AuthContext.Provider value={{ user, token, loading, login, logout, setRole, unreadNotifications, setUnreadNotifications }}>
97	      {children}
98	    </AuthContext.Provider>
99	  );
100	}
101	
102	export function useAuth() {
103	  return useContext(AuthContext);
104	}
