14	  const [saved, setSaved] = useState(false);
15	
16	  useEffect(() => {
17	    apiFetch("/api/profile").then((data) => {
18	      if (data.profile) {
19	        setProfile({
20	          name: data.profile.name || "",
21	          goals: Array.isArray(data.profile.goals) ? data.profile.goals.join("\n") : "",
22	          wakeTime: data.profile.wakeTime || "07:00",
23	          sleepTime: data.profile.sleepTime || "23:00",
24	          customPrompt: data.profile.preferences?.customPrompt || "",
