33	      method: "POST",
34	      body: JSON.stringify({
35	        name: profile.name,
36	        goals: profile.goals.split("\n").filter((g) => g.trim()),
37	        wakeTime: profile.wakeTime,
38	        sleepTime: profile.sleepTime,
