4	
5	export async function GET(request: NextRequest) {
6	  try {
7	    const user = await verifyAuth(request);
8	    const { searchParams } = new URL(request.url);
9	    const type = searchParams.get("type");
10	    const status = searchParams.get("status");
11	    const page = Math.max(1, parseInt(searchParams.get("page") || "1", 10));
12	    const limit = Math.min(50, Math.max(1, parseInt(searchParams.get("limit") || "20", 10)));
13	    const skip = (page - 1) * limit;
14	
15	    const where: Record<string, unknown> = {
16	      applicantId: user.userId,
17	    };
18	
19	    if (type) where.type = type;
20	    if (status) where.status = status;
21	
22	    const [tickets, total] = await Promise.all([
23	      prisma.ticket.findMany({
24	        where: where as any,
25	        orderBy: { createdAt: "desc" },
26	        skip,
27	        take: limit,
28	        include: {
29	          targetAsset: { include: { model: true } },
30	          targetModel: true,
31	        },
32	      }),
33	      prisma.ticket.count({ where: where as any }),
34	    ]);
35	
36	    return Response.json({
37	      tickets,
38	      pagination: { page, limit, total, totalPages: Math.ceil(total / limit) },
39	    });
40	  } catch (e) {
41	    if (e instanceof AuthError) {
42	      return Response.json({ error: e.message }, { status: e.statusCode });
43	    }
44	    return Response.json({ error: "Internal server error" }, { status: 500 });
45	  }
46	}
