10	    const user = await verifyAuth(request);
11	    const { id } = await params;
12	
13	    const ticket = await prisma.ticket.findUnique({
14	      where: { id },
15	      include: {
16	        applicant: { select: { id: true, name: true, email: true, deptId: true } },
17	        targetAsset: { include: { model: true } },
18	        targetModel: true,
19	        assignedBy: { select: { id: true, name: true } },
