21	        fromHolder: { select: { id: true, name: true } },
22	        toHolder: { select: { id: true, name: true } },
23	        deputyApprover: { select: { id: true, name: true } },
24	      },
25	    });
26	
27	    if (!ticket) {
28	      return Response.json({ error: "Ticket not found" }, { status: 404 });
29	    }
30	
31	    // Permission: applicant, their manager, IT_ADMIN, or EXECUTIVE can view
32	    const isApplicant = ticket.applicantId === user.userId;
