1	import { NextRequest } from "next/server";
2	import { prisma } from "@/lib/prisma";
3	import { verifyAuth, requireOneOf, AuthError } from "@/lib/auth";
4	import { callDeepSeek } from "@/lib/ai/client";
5	import { withAiFallback } from "@/lib/ai/with-fallback";
6	
7	interface RecommendItem {
8	  modelId: string;
9	  score: number;
10	  reason: string;
11	}
12	
13	interface RecommendResult {
14	  recommendations: RecommendItem[];
15	  topPick: string | null;
16	}
17	
18	const SYSTEM_PROMPT = `# 角色
19	你是一个IT资产管理系统的设备推荐助手，负责根据员工的需求描述，推荐最合适的办公设备型号。
20	
21	# 输入
22	你将收到：
23	1. 用户的需求描述（自然语言）
24	2. 所有可选的设备型号列表（JSON数组），每个型号包含字段：
25	   - modelId: 型号编码
26	   - category: 设备分类（LAPTOP/MONITOR/KEYBOARD/MOUSE/HEADPHONE/OTHER）
27	   - brandName: 品牌
28	   - modelName: 型号名称
29	   - specs: 规格参数（JSON对象，不同分类键不同）
30	   - stock: 当前可用库存数
31	   - status: 型号状态（ACTIVE或DISCONTINUED）
32	
33	# 任务
34	从型号列表中筛选出最适合用户需求的型号，按匹配度从高到低排序推荐。
35	
36	# 约束
37	1. 必须忽略 status 为 "DISCONTINUED" 的型号
38	2. 如果某个型号的 stock 为 0，推荐理由中必须明确标注"暂无库存"
39	3. 推荐理由必须具体说明该型号的哪些规格/特性匹配了用户的哪些需求
40	4. score 字段为 0-100 的整数，表示匹配程度
41	5. topPick 必须在 recommendations 列表中，且 score 应最高
42	6. 如果没有任何型号匹配，recommendations 返回空数组，topPick 返回 null
43	
44	# 输出格式
45	返回严格的 JSON 对象：
46	{
47	  "recommendations": [
48	    {
49	      "modelId": "型号编码",
50	      "score": 95,
51	      "reason": "推荐理由。若库存为0则追加「暂无库存」"
52	    }
53	  ],
54	  "topPick": "最优型号编码 或 null"
55	}`;
56	
57	export async function POST(request: NextRequest) {
58	  try {
59	    const user = await verifyAuth(request);
60	    requireOneOf(user, "EMPLOYEE", "MANAGER");
61	
62	    const body = (await request.json()) as { requirement?: string };
63	    if (!body.requirement || typeof body.requirement !== "string") {
64	      return Response.json({ error: "requirement is required" }, { status: 400 });
65	    }
66	
67	    const activeModels = await prisma.assetModel.findMany({
68	      where: { status: "ACTIVE" },
69	      include: {
70	        _count: {
71	          select: { instances: { where: { status: "IN_STOCK" } } },
72	        },
73	      },
74	    });
75	
76	    const modelListJson = JSON.stringify(
77	      activeModels.map((m) => ({
78	        modelId: m.id,
79	        category: m.category,
80	        brandName: m.brandName,
81	        modelName: m.modelName,
82	        specs: m.specs,
83	        stock: m._count.instances,
84	        status: m.status,
85	      })),
86	    );
87	
88	    const userPrompt = `用户的设备需求：
89	${body.requirement}
90	
91	当前可用设备型号列表：
92	${modelListJson}
93	
94	请根据用户需求推荐最合适的设备型号。`;
95	
96	    const result = await withAiFallback(
97	      () =>
98	        callDeepSeek<RecommendResult>({
99	          messages: [
100	            { role: "system", content: SYSTEM_PROMPT },
101	            { role: "user", content: userPrompt },
102	          ],
103	        }),
104	      "推荐服务暂时不可用，请稍后重试或浏览全部可用型号自行选择。",
105	    );
106	
107	    if (!result.ok) {
108	      return Response.json(
109	        { recommendations: [], topPick: null, fallback: result.fallback },
110	        { status: 200 },
111	      );
112	    }
113	
114	    return Response.json(result.data, { status: 200 });
115	  } catch (e) {
116	    if (e instanceof AuthError) {
117	      return Response.json({ error: e.message }, { status: e.statusCode });
118	    }
119	    return Response.json({ error: "Internal server error" }, { status: 500 });
120	  }
121	}
