1	import { NextRequest } from "next/server";
2	import { prisma } from "@/lib/prisma";
3	import { verifyAuth, AuthError } from "@/lib/auth";
4	import { WorkflowError } from "@/lib/ticket-workflow";
5	import { logTicketStatusChange, logAssetStatusChange } from "@/lib/audit";
6	import { notifyApprovalResult } from "@/lib/notifications";
7	
8	export async function POST(
9	  request: NextRequest,
10	  { params }: { params: Promise<{ id: string }> }
11	) {
12	  try {
13	    const user = await verifyAuth(request);
14	    const { id } = await params;
15	    const body = await request.json();
16	    const reason = body.reason || "No reason provided";
17	
18	    const result = await prisma.$transaction(async (tx) => {
19	      const ticket = await tx.ticket.findUniqueOrThrow({
20	        where: { id },
21	        include: { applicant: true, targetAsset: true },
22	      });
23	
24	      if (["COMPLETED", "REJECTED", "CANCELLED"].includes(ticket.status)) {
25	        throw new WorkflowError("Ticket is already in a terminal state");
26	      }
27	
28	      // Only allow rejection from pending states
29	      if (!["PENDING_MANAGER_1", "PENDING_MANAGER_2", "PENDING_IT"].includes(ticket.status)) {
30	        throw new WorkflowError(`Cannot reject ticket in status ${ticket.status}`);
31	      }
32	
33	      // Determine if user has permission to reject
34	      const isPendingManager =
35	        ticket.status === "PENDING_MANAGER_1" || ticket.status === "PENDING_MANAGER_2";
36	      const isPendingIt = ticket.status === "PENDING_IT";
37	
38	      if (isPendingManager) {
39	        // Managers can reject their department's tickets; IT_ADMIN can reject any
40	        if (user.role === "MANAGER") {
41	          if (user.deptId !== ticket.applicant.deptId) {
42	            throw new WorkflowError("You can only reject tickets from your own department");
43	          }
44	          if (user.userId === ticket.applicantId) {
45	            throw new WorkflowError("Cannot reject your own ticket");
46	          }
47	        } else if (user.role !== "IT_ADMIN") {
48	          throw new WorkflowError("Only managers or IT_ADMIN can reject tickets");
49	        }
50	      } else if (isPendingIt && user.role !== "IT_ADMIN") {
51	        throw new WorkflowError("Only IT_ADMIN can reject at this stage");
52	      }
53	
54	      const updated = await tx.ticket.update({
55	        where: { id },
56	        data: { status: "REJECTED", rejectReason: reason },
57	      });
58	
59	      // Restore asset status if applicable (§SM-05: reject doesn't change asset for simple cases)
60	      // For RETURN and REPAIR, revert asset status
61	      if (ticket.targetAsset) {
62	        if (ticket.type === "RETURN" && ticket.targetAsset.status === "RETURNING") {
63	          await tx.assetInstance.update({
64	            where: { id: ticket.targetAsset.id },
65	            data: { status: "IN_USE" },
66	          });
67	          await logAssetStatusChange(tx, {
68	            assetId: ticket.targetAsset.id,
69	            operatorId: user.userId,
70	            fromStatus: "RETURNING",
71	            toStatus: "IN_USE",
72	            metadata: { reason: "Ticket rejected" },
73	          });
74	        } else if (ticket.type === "REPAIR" && ticket.targetAsset.status === "REPAIRING") {
75	          await tx.assetInstance.update({
76	            where: { id: ticket.targetAsset.id },
77	            data: { status: "IN_USE" },
78	          });
79	          await logAssetStatusChange(tx, {
80	            assetId: ticket.targetAsset.id,
81	            operatorId: user.userId,
82	            fromStatus: "REPAIRING",
83	            toStatus: "IN_USE",
84	            metadata: { reason: "Ticket rejected" },
85	          });
86	        }
87	      }
88	
89	      await logTicketStatusChange(tx, {
90	        ticketId: id,
91	        operatorId: user.userId,
92	        fromStatus: ticket.status,
93	        toStatus: "REJECTED",
94	        metadata: { rejectReason: reason },
95	      });
96	
97	      await notifyApprovalResult(tx, {
98	        applicantId: ticket.applicantId,
99	        ticketId: id,
100	        approved: false,
101	        ticketType: ticket.type,
102	      });
103	
104	      return updated;
105	    });
106	
107	    return Response.json({ ticket: result });
108	  } catch (e) {
109	    if (e instanceof AuthError) {
110	      return Response.json({ error: e.message }, { status: e.statusCode });
111	    }
112	    if (e instanceof WorkflowError) {
113	      return Response.json({ error: e.message }, { status: 400 });
114	    }
115	    return Response.json({ error: "Internal server error" }, { status: 500 });
116	  }
117	}
