9	export async function POST(request: NextRequest) {
10	  try {
11	    const user = await verifyAuth(request);
12	    requireOneOf(user, "EMPLOYEE", "MANAGER");
13	
14	    const body = await request.json();
15	    const { modelId, reason } = body;
16	
17	    if (!modelId || !reason) {
18	      return Response.json(
19	        { error: "modelId and reason are required" },
20	        { status: 400 }
21	      );
22	    }
23	
24	    const result = await prisma.$transaction(async (tx) => {
25	      const model = await tx.assetModel.findUniqueOrThrow({
26	        where: { id: modelId },
27	      });
28	
29	      if (model.status !== "ACTIVE") {
30	        throw new WorkflowError("Model is discontinued");
31	      }
32	
33	      const dept = await tx.department.findUniqueOrThrow({
34	        where: { id: user.deptId },
35	      });
36	
37	      const initialStatus = TicketWorkflow.determineInitialStatus(Type.APPLY, {
38	        purchasePrice: Number(model.purchasePrice),
39	        applicantRole: user.role,
40	        applicantDeptId: user.deptId,
41	        deptManagerId: dept.managerId,
42	      });
43	
44	      const ticket = await tx.ticket.create({
45	        data: {
46	          type: "APPLY",
47	          status: initialStatus,
48	          applicantId: user.userId,
49	          targetModelId: modelId,
50	          reason,
51	        },
52	      });
53	
54	      await logTicketStatusChange(tx, {
55	        ticketId: ticket.id,
56	        operatorId: user.userId,
57	        fromStatus: "SUBMITTED",
58	        toStatus: initialStatus,
59	        metadata: { modelId, purchasePrice: Number(model.purchasePrice) },
60	      });
61	
62	      // Notify next approver
63	      if (initialStatus === "PENDING_MANAGER_1" && dept.managerId) {
64	        await notifyApprovalRequest(tx, {
65	          managerId: dept.managerId,
66	          ticketId: ticket.id,
67	          applicantName: user.userId,
68	          ticketType: "APPLY",
69	        });
70	      }
71	
72	      return ticket;
73	    });
74	
75	    return Response.json({ ticket: result }, { status: 201 });
76	  } catch (e) {
77	    if (e instanceof AuthError) {
78	      return Response.json({ error: e.message }, { status: e.statusCode });
79	    }
80	    if (e instanceof WorkflowError) {
81	      return Response.json({ error: e.message }, { status: 400 });
