1	import { jwtVerify } from "jose";
2	import type { NextRequest } from "next/server";
3	
4	export interface AuthUser {
5	  userId: string;
6	  role: "EMPLOYEE" | "MANAGER" | "IT_ADMIN" | "EXECUTIVE";
7	  deptId: string;
8	}
9	
10	function getSecret(): Uint8Array {
11	  return new TextEncoder().encode(
12	    process.env.AUTH_SECRET || "dev-secret-change-in-production"
13	  );
14	}
15	
16	export class AuthError extends Error {
17	  constructor(
18	    message: string,
19	    public statusCode: number = 401
20	  ) {
21	    super(message);
22	    this.name = "AuthError";
23	  }
24	}
25	
26	export async function verifyAuth(request: NextRequest): Promise<AuthUser> {
27	  const authHeader = request.headers.get("authorization");
28	  if (!authHeader?.startsWith("Bearer ")) {
29	    throw new AuthError("Missing or invalid authorization header", 401);
30	  }
31	  const token = authHeader.slice(7);
32	  try {
33	    const { payload } = await jwtVerify(token, getSecret());
34	    const role = payload.role as string;
35	    if (!["EMPLOYEE", "MANAGER", "IT_ADMIN", "EXECUTIVE"].includes(role)) {
36	      throw new AuthError("Invalid role in token", 401);
37	    }
38	    return {
39	      userId: payload.sub as string,
40	      role: role as AuthUser["role"],
41	      deptId: payload.deptId as string,
42	    };
43	  } catch (e) {
44	    if (e instanceof AuthError) throw e;
45	    throw new AuthError("Invalid or expired token", 401);
46	  }
47	}
48	
49	export function requireRole(
50	  user: AuthUser,
51	  ...roles: AuthUser["role"][]
52	): void {
53	  if (!roles.includes(user.role)) {
54	    throw new AuthError("Insufficient permissions", 403);
55	  }
56	}
57	
58	export function requireOneOf(
59	  user: AuthUser,
60	  ...roles: AuthUser["role"][]
61	): void {
62	  if (!roles.includes(user.role)) {
63	    throw new AuthError("Insufficient permissions", 403);
64	  }
65	}
