"use client";

/**
 * 登录页面
 * 功能: 邮箱+密码登录，成功后跳转 /home
 */

import { useState, FormEvent } from "react";
import { useRouter } from "next/navigation";
import { useAuth } from "@/lib/auth-context";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from "@/components/ui/card";
import { LogIn, Loader2 } from "lucide-react";

export default function LoginPage() {
  const router = useRouter();
  const { login, token, loading: authLoading } = useAuth();

  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [error, setError] = useState("");
  const [submitting, setSubmitting] = useState(false);

  // Already logged in -> redirect to /home
  if (!authLoading && token) {
    router.replace("/home");
    return null;
  }

  const handleSubmit = async (e: FormEvent) => {
    e.preventDefault();
    setError("");

    if (!email.trim() || !password.trim()) {
      setError("请输入邮箱和密码");
      return;
    }

    setSubmitting(true);
    try {
      await login(email, password);
      router.push("/home");
    } catch (err: unknown) {
      const message =
        err instanceof Error ? err.message : "登录失败，请检查邮箱和密码";
      setError(message);
    } finally {
      setSubmitting(false);
    }
  };

  // Show nothing while checking auth state
  if (authLoading) {
    return (
      <div className="min-h-screen flex items-center justify-center">
        <Loader2 className="w-8 h-8 animate-spin text-muted-foreground" />
      </div>
    );
  }

  return (
    <div className="min-h-screen flex items-center justify-center px-4 bg-muted/30">
      <Card className="w-full max-w-md">
        <CardHeader className="text-center">
          <CardTitle className="text-2xl font-bold">资产管理系统</CardTitle>
          <CardDescription>请使用公司邮箱登录</CardDescription>
        </CardHeader>
        <CardContent>
          <form onSubmit={handleSubmit} className="space-y-4">
            <div className="space-y-2">
              <label htmlFor="email" className="text-sm font-medium">
                邮箱
              </label>
              <Input
                id="email"
                type="email"
                placeholder="your@company.com"
                value={email}
                onChange={(e) => setEmail(e.target.value)}
                autoComplete="email"
                disabled={submitting}
              />
            </div>

            <div className="space-y-2">
              <label htmlFor="password" className="text-sm font-medium">
                密码
              </label>
              <Input
                id="password"
                type="password"
                placeholder="请输入密码"
                value={password}
                onChange={(e) => setPassword(e.target.value)}
                autoComplete="current-password"
                disabled={submitting}
              />
            </div>

            {error && (
              <div className="text-sm text-destructive bg-destructive/10 rounded-lg px-3 py-2">
                {error}
              </div>
            )}

            <Button type="submit" className="w-full" disabled={submitting}>
              {submitting ? (
                <Loader2 className="w-4 h-4 mr-2 animate-spin" />
              ) : (
                <LogIn className="w-4 h-4 mr-2" />
              )}
              {submitting ? "登录中..." : "登录"}
            </Button>
          </form>
        </CardContent>
      </Card>
    </div>
  );
}

"use client";

/**
 * 工作台首页 (所有角色)
 * 功能: 快捷入口 + 我的资产/工单/通知摘要 (从 API 获取)
 */

import { useState, useEffect } from "react";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Skeleton } from "@/components/ui/skeleton";
import RoleGuard from "@/components/role-guard";
import { useAuth } from "@/lib/auth-context";
import { apiFetch } from "@/lib/api-client";
import {
  Laptop,
  ClipboardPlus,
  Wrench,
  Bot,
  Ticket,
  Bell,
  Package,
  CheckSquare,
  AlertTriangle,
  RefreshCw,
} from "lucide-react";
import Link from "next/link";
import { format, isAfter, addMonths } from "date-fns";

// ---- Types ----

interface AssetModel {
  id: string;
  category: string;
  brandName: string;
  modelName: string;
  specs: unknown;
  warrantyMonths: number;
  status: string;
}

interface AssetInstance {
  id: string;
  status: string;
  holderId: string;
  deptId: string;
  purchaseDate: string;
  warrantyExpiry: string;
  createdAt: string;
  updatedAt: string;
  model?: AssetModel;
}

interface TicketItem {
  id: string;
  type: string;
  status: string;
  reason: string;
  createdAt: string;
}

interface PaginatedAssets {
  assets: AssetInstance[];
  pagination: { page: number; limit: number; total: number; totalPages: number };
}

interface PaginatedTickets {
  tickets: TicketItem[];
  pagination: { page: number; limit: number; total: number; totalPages: number };
}

// ---- Quick Actions ----

const quickActions = [
  { label: "申领设备", href: "/apply", icon: ClipboardPlus, color: "bg-blue-50 text-blue-700", roles: ["EMPLOYEE", "MANAGER"] as const },
  { label: "我的资产", href: "/my-assets", icon: Laptop, color: "bg-green-50 text-green-700", roles: ["EMPLOYEE", "MANAGER"] as const },
  { label: "报修", href: "/tickets?type=repair", icon: Wrench, color: "bg-orange-50 text-orange-700", roles: ["EMPLOYEE", "MANAGER"] as const },
  { label: "AI 助手", href: "/chat", icon: Bot, color: "bg-purple-50 text-purple-700", roles: ["EMPLOYEE", "MANAGER", "IT_ADMIN", "EXECUTIVE"] as const },
  { label: "我的工单", href: "/tickets", icon: Ticket, color: "bg-indigo-50 text-indigo-700", roles: ["EMPLOYEE", "MANAGER"] as const },
  { label: "通知中心", href: "/notifications", icon: Bell, color: "bg-pink-50 text-pink-700", roles: ["EMPLOYEE", "MANAGER", "IT_ADMIN", "EXECUTIVE"] as const },
  { label: "审批工作台", href: "/approvals", icon: CheckSquare, color: "bg-amber-50 text-amber-700", roles: ["MANAGER"] as const },
  { label: "IT 工作台", href: "/it/home", icon: Package, color: "bg-cyan-50 text-cyan-700", roles: ["IT_ADMIN"] as const },
];

// ---- Helpers ----

function getWarrantyExpiringSoon(assets: AssetInstance[]): number {
  const now = new Date();
  const threeMonthsFromNow = addMonths(now, 3);
  return assets.filter((a) => {
    if (!a.warrantyExpiry) return false;
    const expiry = new Date(a.warrantyExpiry);
    return isAfter(threeMonthsFromNow, expiry) && isAfter(expiry, now);
  }).length;
}

function countPendingTickets(tickets: TicketItem[]): number {
  const pendingStatuses = ["SUBMITTED", "PENDING_MANAGER_1", "PENDING_MANAGER_2", "PENDING_IT"];
  return tickets.filter((t) => pendingStatuses.includes(t.status)).length;
}

// ---- Component ----

export default function HomePage() {
  const { user } = useAuth();
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState("");
  const [assets, setAssets] = useState<AssetInstance[]>([]);
  const [tickets, setTickets] = useState<TicketItem[]>([]);
  const [totalAssets, setTotalAssets] = useState(0);
  const [totalTickets, setTotalTickets] = useState(0);

  const fetchData = async () => {
    setLoading(true);
    setError("");
    try {
      const [assetsRes, ticketsRes] = await Promise.all([
        apiFetch<PaginatedAssets>("/api/assets/mine"),
        apiFetch<PaginatedTickets>("/api/tickets?limit=5"),
      ]);
      setAssets(assetsRes.assets || []);
      setTotalAssets(assetsRes.pagination?.total || 0);
      setTickets(ticketsRes.tickets || []);
      setTotalTickets(ticketsRes.pagination?.total || 0);
    } catch (err: unknown) {
      setError(err instanceof Error ? err.message : "加载失败");
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchData();
  }, []);

  // ---- Loading ----
  if (loading) {
    return (
      <div className="max-w-6xl mx-auto space-y-8">
        <div className="space-y-2">
          <Skeleton className="h-8 w-48" />
          <Skeleton className="h-4 w-64" />
        </div>
        <div className="grid gap-4 grid-cols-2 sm:grid-cols-3 lg:grid-cols-4">
          {Array.from({ length: 8 }).map((_, i) => (
            <Skeleton key={i} className="h-32 rounded-xl" />
          ))}
        </div>
        <Skeleton className="h-48 rounded-xl" />
      </div>
    );
  }

  // ---- Error ----
  if (error) {
    return (
      <div className="max-w-6xl mx-auto">
        <div className="flex flex-col items-center justify-center py-16 text-center">
          <AlertTriangle className="w-12 h-12 text-destructive mb-4" />
