        </p>
      </div>

      {/* Quick Actions */}
      <div>
        <h2 className="text-sm font-medium text-muted-foreground mb-3">快捷入口</h2>
        <div className="grid gap-4 grid-cols-2 sm:grid-cols-3 lg:grid-cols-4">
          {quickActions.map((action) => (
            <RoleGuard key={action.label} roles={[...action.roles]}>
              <Link href={action.href}>
                <Card className="hover:shadow-md transition-shadow cursor-pointer h-full">
                  <CardContent className="flex flex-col items-center justify-center p-6 gap-3">
                    <div className={`w-12 h-12 rounded-xl flex items-center justify-center ${action.color}`}>
                      <action.icon className="w-6 h-6" />
                    </div>
                    <span className="text-sm font-medium">{action.label}</span>
                  </CardContent>
                </Card>
              </Link>
            </RoleGuard>
          ))}
        </div>
      </div>

      {/* Employee / Manager: My Summary */}
      <RoleGuard roles={["EMPLOYEE", "MANAGER"]}>
        <Card>
          <CardHeader>
            <CardTitle className="text-base">我的概览</CardTitle>
          </CardHeader>
          <CardContent>
            <div className="space-y-3">
              <Link href="/my-assets" className="flex items-center justify-between p-3 rounded-lg hover:bg-muted transition-colors">
                <span className="text-sm">我的资产</span>
                <span className="text-lg font-bold text-primary">{totalAssets}</span>
              </Link>

              <Link href="/tickets" className="flex items-center justify-between p-3 rounded-lg hover:bg-muted transition-colors">
                <span className="text-sm">待处理工单</span>
                <span className="text-lg font-bold text-orange-500">{pendingCount}</span>
              </Link>

              <Link href="/tickets" className="flex items-center justify-between p-3 rounded-lg hover:bg-muted transition-colors">
                <span className="text-sm">全部工单</span>
                <span className="text-lg font-bold text-primary">{totalTickets}</span>
              </Link>

              {warrantyExpiring > 0 && (
                <Link href="/my-assets" className="flex items-center justify-between p-3 rounded-lg hover:bg-muted transition-colors">
                  <span className="text-sm text-orange-600">保修即将到期</span>
                  <span className="text-lg font-bold text-orange-500">{warrantyExpiring}</span>
                </Link>
              )}

              {totalAssets === 0 && pendingCount === 0 && (
                <div className="text-sm text-muted-foreground py-4 text-center">
                  暂无待办事项
