      </RoleGuard>

      {/* IT Admin Summary */}
      <RoleGuard roles={["IT_ADMIN"]}>
        <div className="grid gap-4 grid-cols-1 sm:grid-cols-2 lg:grid-cols-4">
          {[
            { label: "待处理工单", value: String(pendingCount), href: "/it/tickets" },
            { label: "在库资产", value: String(totalAssets), href: "/it/assets" },
            { label: "全部工单", value: String(totalTickets), href: "/it/tickets" },
          ].map((stat) => (
            <Link key={stat.label} href={stat.href}>
              <Card className="hover:shadow-md transition-shadow">
                <CardContent className="p-6">
                  <p className="text-sm text-muted-foreground">{stat.label}</p>
                  <p className="text-3xl font-bold mt-1">{stat.value}</p>
                </CardContent>
              </Card>
            </Link>
          ))}
        </div>
      </RoleGuard>

      {/* Executive teaser */}
      <RoleGuard roles={["EXECUTIVE"]}>
        <Card>
          <CardHeader>
            <CardTitle className="text-base">全公司资产概览</CardTitle>
          </CardHeader>
          <CardContent>
            <div className="grid gap-4 grid-cols-2 sm:grid-cols-4">
              {[
                { label: "我的资产", value: String(totalAssets) },
                { label: "工单总数", value: String(totalTickets) },
                { label: "待处理", value: String(pendingCount) },
                { label: "保修到期提醒", value: String(warrantyExpiring) },
              ].map((stat) => (
                <div key={stat.label} className="text-center p-4 rounded-lg bg-muted">
                  <p className="text-2xl font-bold">{stat.value}</p>
                  <p className="text-xs text-muted-foreground mt-1">{stat.label}</p>
                </div>
              ))}
            </div>
          </CardContent>
        </Card>
      </RoleGuard>
    </div>
  );
}

"use client";

/**
 * 我的资产列表 (员工/主管)
 * 功能: 从 /api/assets/mine 获取当前用户的资产，带分页
 */

import { useState, useEffect } from "react";
import { Card, CardContent } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Skeleton } from "@/components/ui/skeleton";
import EmptyState from "@/components/empty-state";
import AssetStatusBadge from "@/components/asset-status-badge";
import type { AssetStatus } from "@/components/asset-status-badge";
import { apiFetch } from "@/lib/api-client";
import { Laptop, AlertTriangle, RefreshCw, ChevronLeft, ChevronRight } from "lucide-react";
import { format } from "date-fns";

// ---- Types ----

interface AssetModel {
  id: string;
  category: string;
  brandName: string;
  modelName: string;
  specs: unknown;
  warrantyMonths: number;
  status: string;
}

interface AssetInstance {
  id: string;
  status: string;
  holderId: string;
  deptId: string;
  purchaseDate: string;
  warrantyExpiry: string;
  createdAt: string;
  updatedAt: string;
  model?: AssetModel;
}

interface PaginatedAssets {
  assets: AssetInstance[];
  pagination: { page: number; limit: number; total: number; totalPages: number };
}

// ---- Component ----

export default function MyAssetsPage() {
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState("");
  const [assets, setAssets] = useState<AssetInstance[]>([]);
  const [page, setPage] = useState(1);
  const [totalPages, setTotalPages] = useState(1);
  const limit = 10;

  const fetchAssets = async (p: number) => {
    setLoading(true);
    setError("");
    try {
      const data = await apiFetch<PaginatedAssets>(
        `/api/assets/mine?page=${p}&limit=${limit}`
      );
      setAssets(data.assets || []);
      setTotalPages(data.pagination?.totalPages || 1);
    } catch (err: unknown) {
      setError(err instanceof Error ? err.message : "加载资产列表失败");
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchAssets(page);
  }, [page]);

  // ---- Loading ----
  if (loading) {
    return (
      <div className="max-w-4xl mx-auto space-y-6">
        <div className="space-y-2">
          <Skeleton className="h-8 w-48" />
          <Skeleton className="h-4 w-64" />
        </div>
        <div className="space-y-3">
          {Array.from({ length: 3 }).map((_, i) => (
            <Skeleton key={i} className="h-24 rounded-xl" />
          ))}
        </div>
      </div>
    );
  }

  // ---- Error ----
  if (error) {
    return (
      <div className="max-w-4xl mx-auto flex flex-col items-center justify-center py-16 text-center">
        <AlertTriangle className="w-12 h-12 text-destructive mb-4" />
        <h2 className="text-lg font-semibold mb-2">加载失败</h2>
        <p className="text-sm text-muted-foreground mb-4">{error}</p>
        <Button variant="outline" onClick={() => fetchAssets(page)}>
          <RefreshCw className="w-4 h-4 mr-2" />
          重试
        </Button>
      </div>
    );
  }

  return (
    <div className="max-w-4xl mx-auto space-y-6">
      <div>
        <h1 className="text-2xl font-bold tracking-tight">我的资产</h1>
        <p className="text-muted-foreground mt-1">查看你当前持有的所有设备</p>
      </div>

      {assets.length === 0 ? (
        <EmptyState
          icon={Laptop}
          title="你目前没有持有任何设备"
          description="你可以去申领一台你需要的设备，或者查看可用的设备列表。"
          actionLabel="去申领设备"
          actionHref="/apply"
        />
      ) : (
        <>
          <div className="space-y-3">
            {assets.map((asset) => (
              <Card key={asset.id} className="hover:shadow-md transition-shadow">
                <CardContent className="p-4 flex items-center justify-between">
                  <div className="flex items-center gap-4">
                    <div className="w-10 h-10 rounded-lg bg-muted flex items-center justify-center">
                      <Laptop className="w-5 h-5 text-muted-foreground" />
                    </div>
                    <div>
                      <p className="font-medium">
                        {asset.model?.modelName || "未知型号"}
                      </p>
                      <p className="text-sm text-muted-foreground">
                        {asset.model?.brandName || ""}
                        {asset.model?.category ? ` | ${asset.model.category}` : ""}
                      </p>
                    </div>
                  </div>
                  <div className="flex items-center gap-3">
                    <AssetStatusBadge status={asset.status as AssetStatus} />
                    <span className="text-xs text-muted-foreground">
                      {asset.warrantyExpiry
                        ? `保修至 ${format(new Date(asset.warrantyExpiry), "yyyy-MM-dd")}`
                        : ""}
                    </span>
                  </div>
                </CardContent>
              </Card>
            ))}
          </div>

          {/* Pagination */}
          {totalPages > 1 && (
            <div className="flex items-center justify-center gap-4 pt-4">
              <Button
                variant="outline"
                size="sm"
                onClick={() => setPage((p) => Math.max(1, p - 1))}
                disabled={page <= 1}
              >
                <ChevronLeft className="w-4 h-4 mr-1" />
                上一页
              </Button>
              <span className="text-sm text-muted-foreground">
                第 {page} / {totalPages} 页
              </span>
              <Button
                variant="outline"
                size="sm"
                onClick={() => setPage((p) => Math.min(totalPages, p + 1))}
                disabled={page >= totalPages}
              >
                下一页
                <ChevronRight className="w-4 h-4 ml-1" />
              </Button>
            </div>
          )}
        </>
      )}
    </div>
  );
}

"use client";

/**
 * 申领设备 (员工/主管)
 * 功能: 输入需求描述 → AI推荐型号 → 选择型号 → 填写理由 → 提交申领
 */

import { useState, FormEvent } from "react";
import { useRouter } from "next/navigation";
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Textarea } from "@/components/ui/textarea";
import { Badge } from "@/components/ui/badge";
import { Skeleton } from "@/components/ui/skeleton";
import { apiFetch, ApiError } from "@/lib/api-client";
import { Bot, Sparkles, Send, Loader2, AlertTriangle } from "lucide-react";

// ---- Types ----

interface RecommendItem {
  modelId: string;
  score: number;
  reason: string;
}

interface RecommendResult {
  recommendations: RecommendItem[];
  topPick: string | null;
  fallback?: string;
}

// ---- Component ----

export default function ApplyPage() {
  const router = useRouter();

  const [description, setDescription] = useState("");
  const [isSearching, setIsSearching] = useState(false);
  const [recommendError, setRecommendError] = useState("");
  const [recommendations, setRecommendations] = useState<RecommendItem[]>([]);
  const [selectedModel, setSelectedModel] = useState<string | null>(null);
  const [reason, setReason] = useState("");
  const [submitting, setSubmitting] = useState(false);
  const [submitError, setSubmitError] = useState("");

  const handleSearch = async () => {
    if (!description.trim()) return;
    setIsSearching(true);
    setRecommendError("");
    setRecommendations([]);
    setSelectedModel(null);

    try {
      const data = await apiFetch<RecommendResult>("/api/ai/recommend", {
        method: "POST",
        body: JSON.stringify({ requirement: description }),
      });
      setRecommendations(data.recommendations || []);
      if (data.recommendations.length === 0 && data.fallback) {
        setRecommendError(data.fallback);
      }
    } catch (err: unknown) {
      const message =
        err instanceof Error ? err.message : "AI 推荐请求失败，请稍后重试";
      setRecommendError(message);
    } finally {
      setIsSearching(false);
    }
  };

  const handleSubmit = async (e: FormEvent) => {
    e.preventDefault();
    if (!selectedModel || !reason.trim()) return;

    setSubmitting(true);
    setSubmitError("");

    try {
      const data = await apiFetch<{ ticket: { id: string } }>("/api/tickets/apply", {
        method: "POST",
        body: JSON.stringify({ modelId: selectedModel, reason: reason.trim() }),
      });
      router.push(`/tickets/${data.ticket.id}`);
    } catch (err: unknown) {
      const message =
        err instanceof ApiError ? err.message : "提交申领失败，请稍后重试";
      setSubmitError(message);
    } finally {
      setSubmitting(false);
    }
  };

  return (
    <div className="max-w-3xl mx-auto space-y-6">
      <div>
        <h1 className="text-2xl font-bold tracking-tight">申领设备</h1>
        <p className="text-muted-foreground mt-1">
          描述你的需求，AI 将为你推荐最合适的设备
        </p>
      </div>

      {/* AI Recommend Card */}
      <Card>
        <CardHeader>
          <CardTitle className="text-base flex items-center gap-2">
            <Bot className="w-5 h-5 text-primary" />
            AI 智能推荐
          </CardTitle>
          <CardDescription>
            用自然语言描述你的工作需求，系统将自动匹配最佳设备型号
          </CardDescription>
        </CardHeader>
        <CardContent className="space-y-4">
          <div className="flex gap-2">
            <Input
              placeholder="例如: 我需要一台用于前端开发的笔记本，16GB内存以上，轻薄便携..."
              value={description}
              onChange={(e) => setDescription(e.target.value)}
              onKeyDown={(e) => e.key === "Enter" && handleSearch()}
              className="flex-1"
              disabled={isSearching}
            />
            <Button
              onClick={handleSearch}
              disabled={!description.trim() || isSearching}
            >
              {isSearching ? (
                <Loader2 className="w-4 h-4 mr-1 animate-spin" />
              ) : (
                <Sparkles className="w-4 h-4 mr-1" />
              )}
              {isSearching ? "分析中..." : "AI 推荐"}
            </Button>
          </div>

          {/* Loading skeleton */}
          {isSearching && (
            <div className="space-y-3">
              {Array.from({ length: 3 }).map((_, i) => (
                <Skeleton key={i} className="h-20 rounded-lg" />
              ))}
            </div>
          )}

          {/* Recommendations */}
          {!isSearching && recommendations.length > 0 && (
            <div className="space-y-3">
              <p className="text-sm font-medium text-muted-foreground">
                AI 推荐结果
              </p>
              {recommendations.map((rec) => (
                <div
                  key={rec.modelId}
                  className={`p-4 rounded-lg border-2 cursor-pointer transition-all ${
                    selectedModel === rec.modelId
                      ? "border-primary bg-secondary"
                      : "border-border hover:border-primary/50"
                  }`}
                  onClick={() => setSelectedModel(rec.modelId)}
                >
                  <div className="flex items-start justify-between">
                    <div className="flex-1">
                      <div className="flex items-center gap-2">
                        <p className="font-medium">{rec.modelId}</p>
                        <Badge variant={rec.score >= 90 ? "success" : "blue"}>
                          匹配度 {Math.round(rec.score)}%
                        </Badge>
                      </div>
                      <p className="text-xs text-primary mt-1">{rec.reason}</p>
                    </div>
                  </div>
                </div>
              ))}
            </div>
          )}

          {/* Recommend error */}
          {!isSearching && recommendError && (
            <div className="flex items-start gap-2 p-3 rounded-lg bg-destructive/10 text-destructive text-sm">
              <AlertTriangle className="w-4 h-4 mt-0.5 flex-shrink-0" />
              <span>{recommendError}</span>
            </div>
          )}

          {/* No search yet */}
          {!isSearching && recommendations.length === 0 && !recommendError && (
            <div className="text-center py-8 text-muted-foreground">
              <Bot className="w-12 h-12 mx-auto mb-2 opacity-30" />
              <p className="text-sm">在上方输入你的工作需求，点击 AI 推荐</p>
              <p className="text-xs mt-1">
                系统将根据你的需求智能匹配可用设备
              </p>
            </div>
          )}
        </CardContent>
      </Card>

      {/* Submit Section */}
      <Card>
        <CardHeader>
          <CardTitle className="text-base">申领信息</CardTitle>
          <CardDescription>
            请填写申领理由，提交后将进入审批流程
          </CardDescription>
        </CardHeader>
        <CardContent className="space-y-4">
          <form onSubmit={handleSubmit} className="space-y-4">
            <div>
              <label className="text-sm font-medium mb-1 block">已选型号</label>
              <div className="p-3 rounded-lg bg-muted text-sm">
                {selectedModel || "请先在上方选择推荐的型号"}
              </div>
            </div>

            <div>
              <label className="text-sm font-medium mb-1 block">
                申领理由 <span className="text-destructive">*</span>
              </label>
              <Textarea
                placeholder="请详细说明你需要该设备的理由，这将帮助审批人快速了解你的需求..."
                value={reason}
                onChange={(e) => setReason(e.target.value)}
                rows={4}
                disabled={submitting}
              />
            </div>

            {submitError && (
              <div className="p-3 rounded-lg bg-destructive/10 text-destructive text-sm">
                {submitError}
              </div>
            )}

            <div className="flex justify-end">
              <Button
                type="submit"
                disabled={!selectedModel || !reason.trim() || submitting}
                className="w-full sm:w-auto"
              >
                {submitting ? (
                  <Loader2 className="w-4 h-4 mr-1 animate-spin" />
                ) : (
                  <Send className="w-4 h-4 mr-1" />
                )}
                {submitting ? "提交中..." : "提交申领"}
              </Button>
            </div>
          </form>
        </CardContent>
      </Card>
    </div>
  );
}

