// ---- Types ----

interface TicketData {
  id: string;
  type: string;
  status: string;
  reason: string;
  rejectReason?: string;
  applicantId: string;
  targetModelId?: string;
  targetAssetId?: string;
  createdAt: string;
  updatedAt: string;
  applicant?: { id: string; name: string; email: string; deptId: string };
  targetModel?: { id: string; modelName: string; brandName: string; category: string };
  targetAsset?: { id: string; status: string; model?: { id: string; modelName: string; brandName: string } };
  processor?: { id: string; name: string };
  assignedBy?: { id: string; name: string };
}

interface AuditLogItem {
  id: string;
  action: string;
  createdAt: string;
  operator?: { id: string; name: string };
  metadata?: Record<string, unknown>;
}

interface TicketDetailResponse {
  ticket: TicketData;
  timeline: AuditLogItem[];
}

// ---- Labels ----

const statusLabels: Record<string, string> = {
  SUBMITTED: "已提交",
  PENDING_MANAGER_1: "待主管审批",
  PENDING_MANAGER_2: "待主管审批",
  PENDING_IT: "待IT处理",
  APPROVED: "已通过",
  REJECTED: "已驳回",
  IN_PROGRESS: "处理中",
  COMPLETED: "已完成",
  CANCELLED: "已取消",
};

const statusVariants: Record<string, "blue" | "orange" | "green" | "red" | "gray" | "purple"> = {
  SUBMITTED: "blue",
  PENDING_MANAGER_1: "orange",
  PENDING_MANAGER_2: "orange",
  PENDING_IT: "orange",
  APPROVED: "green",
  REJECTED: "red",
  IN_PROGRESS: "purple",
  COMPLETED: "green",
  CANCELLED: "gray",
};

const typeLabels: Record<string, string> = {
  APPLY: "申领",
  RETURN: "归还",
  REPAIR: "报修",
  TRANSFER: "调拨",
};

// ---- Helpers ----

function buildTimeline(
  ticket: TicketData,
  auditLogs: AuditLogItem[]
): TimelineEvent[] {
  // Start with the creation event
  const events: TimelineEvent[] = [
    {
      id: "create",
      status: "completed",
      title: "提交工单",
      description: ticket.reason,
      timestamp: format(new Date(ticket.createdAt), "yyyy-MM-dd HH:mm"),
      actor: ticket.applicant?.name,
    },
  ];

  // Add audit log events
  for (const log of auditLogs) {
    let title = log.action || "状态变更";
    let status: TimelineEvent["status"] = "completed";

    const fromStatus = (log.metadata?.fromStatus as string) || "";
    const toStatus = (log.metadata?.toStatus as string) || "";

    if (toStatus === "REJECTED") {
      title = "工单被驳回";
      status = "rejected";
      if (log.metadata?.rejectReason) {
        title += `: ${log.metadata.rejectReason}`;
      }
    } else if (toStatus === "CANCELLED") {
      title = "工单已取消";
      status = "cancelled";
    } else if (toStatus === "COMPLETED") {
      title = "工单已完成";
      status = "completed";
    } else if (toStatus === "APPROVED") {
      title = "审批通过";
      status = "completed";
    } else if (toStatus === "IN_PROGRESS") {
      title = "开始处理";
      status = "completed";
    } else if (toStatus === "PENDING_IT") {
      title = "待IT处理";
      status = "completed";
    } else if (fromStatus.includes("PENDING_MANAGER") && toStatus === "PENDING_IT") {
      title = "主管审批通过";
      status = "completed";
    } else if (fromStatus === "SUBMITTED" && toStatus.includes("PENDING_MANAGER")) {
      title = "提交审批";
      status = "completed";
    }

    events.push({
      id: log.id,
      status,
      title,
      timestamp: format(new Date(log.createdAt), "yyyy-MM-dd HH:mm"),
      actor: log.operator?.name,
    });
  }

  // Add pending/current state for in-progress tickets
  const terminalStatuses = ["COMPLETED", "REJECTED", "CANCELLED"];
  if (!terminalStatuses.includes(ticket.status)) {
    events.push({
      id: "current-state",
      status: "current",
      title: statusLabels[ticket.status] || ticket.status,
      description: "等待处理中...",
    });
  }

  return events;
}

// ---- Component ----

export default function TicketDetailPage() {
  const params = useParams();
  const router = useRouter();
  const { user } = useAuth();
  const ticketId = params.id as string;

  const [loading, setLoading] = useState(true);
  const [error, setError] = useState("");
  const [ticket, setTicket] = useState<TicketData | null>(null);
  const [timeline, setTimeline] = useState<TimelineEvent[]>([]);
  const [actionLoading, setActionLoading] = useState<string | null>(null);
  const [actionError, setActionError] = useState("");

  const fetchTicket = async () => {
    setLoading(true);
    setError("");
    try {
      const data = await apiFetch<TicketDetailResponse>(`/api/tickets/${ticketId}`);
      setTicket(data.ticket);
      setTimeline(buildTimeline(data.ticket, data.timeline || []));
    } catch (err: unknown) {
      if (err instanceof ApiError && err.status === 404) {
        setError("工单不存在");
      } else {
        setError(err instanceof Error ? err.message : "加载工单详情失败");
      }
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchTicket();
  }, [ticketId]);

  // ---- Actions ----

  const handleApprove = async () => {
    setActionLoading("approve");
    setActionError("");
    try {
      await apiFetch(`/api/tickets/${ticketId}/approve`, { method: "POST" });
      fetchTicket();
    } catch (err: unknown) {
      setActionError(err instanceof Error ? err.message : "审批失败");
    } finally {
      setActionLoading(null);
    }
  };

  const handleReject = async () => {
    setActionLoading("reject");
    setActionError("");
    try {
      await apiFetch(`/api/tickets/${ticketId}/reject`, {
        method: "POST",
        body: JSON.stringify({ reason: "审批驳回" }),
      });
      fetchTicket();
    } catch (err: unknown) {
      setActionError(err instanceof Error ? err.message : "驳回失败");
    } finally {
      setActionLoading(null);
    }
  };

  const handleCancel = async () => {
    setActionLoading("cancel");
    setActionError("");
    try {
      await apiFetch(`/api/tickets/${ticketId}/cancel`, { method: "POST" });
      fetchTicket();
    } catch (err: unknown) {
      setActionError(err instanceof Error ? err.message : "取消失败");
    } finally {
      setActionLoading(null);
    }
  };

  // ---- Determine if actions are available ----

  const isTerminal =
    ticket?.status === "COMPLETED" ||
    ticket?.status === "REJECTED" ||
    ticket?.status === "CANCELLED";

  const isPendingManager =
    ticket?.status === "PENDING_MANAGER_1" ||
    ticket?.status === "PENDING_MANAGER_2";

  const canApprove =
    !isTerminal &&
    ((isPendingManager &&
      (user.role === "MANAGER" || user.role === "IT_ADMIN")) ||
      (ticket?.status === "PENDING_IT" && user.role === "IT_ADMIN"));

  const canCancel =
    !isTerminal &&
    ticket?.applicantId === user.id &&
    ticket?.status !== "APPROVED" &&
    ticket?.status !== "IN_PROGRESS";

  // ---- Loading ----
  if (loading) {
    return (
      <div className="max-w-3xl mx-auto space-y-6">
        <div className="space-y-2">
          <Skeleton className="h-8 w-48" />
          <Skeleton className="h-4 w-64" />
        </div>
        <Skeleton className="h-64 rounded-xl" />
        <Skeleton className="h-48 rounded-xl" />
      </div>
    );
  }

  // ---- Not Found ----
  if (error === "工单不存在") {
    return (
      <div className="max-w-3xl mx-auto flex flex-col items-center justify-center py-16 text-center">
        <FileText className="w-12 h-12 text-muted-foreground mb-4" />
        <h2 className="text-lg font-semibold mb-2">工单不存在</h2>
        <p className="text-sm text-muted-foreground mb-4">
          没有找到工单 {ticketId}
        </p>
        <Link href="/tickets">
          <Button variant="outline">
            <ArrowLeft className="w-4 h-4 mr-2" />
            返回工单列表
          </Button>
        </Link>
      </div>
    );
  }

  // ---- Error ----
  if (error || !ticket) {
    return (
      <div className="max-w-3xl mx-auto flex flex-col items-center justify-center py-16 text-center">
        <AlertTriangle className="w-12 h-12 text-destructive mb-4" />
        <h2 className="text-lg font-semibold mb-2">加载失败</h2>
        <p className="text-sm text-muted-foreground mb-4">{error || "未知错误"}</p>
        <Button variant="outline" onClick={fetchTicket}>
          <RefreshCw className="w-4 h-4 mr-2" />
          重试
        </Button>
      </div>
    );
  }

  return (
    <div className="max-w-3xl mx-auto space-y-6">
      {/* Header */}
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-2xl font-bold tracking-tight">工单详情</h1>
          <p className="text-muted-foreground mt-1">工单编号: {ticket.id}</p>
        </div>
        <Badge variant={statusVariants[ticket.status] || "gray"} className="text-sm px-3 py-1">
          {typeLabels[ticket.type] || ticket.type} - {statusLabels[ticket.status] || ticket.status}
        </Badge>
      </div>

      {/* Info Card */}
      <Card>
        <CardHeader>
          <CardTitle className="text-base flex items-center gap-2">
            <FileText className="w-5 h-5 text-muted-foreground" />
            基本信息
          </CardTitle>
        </CardHeader>
        <CardContent>
          <dl className="grid grid-cols-2 gap-4 text-sm">
            <div>
              <dt className="text-muted-foreground">工单编号</dt>
              <dd className="font-medium">{ticket.id}</dd>
            </div>
            <div>
              <dt className="text-muted-foreground">工单类型</dt>
              <dd className="font-medium">{typeLabels[ticket.type] || ticket.type}</dd>
            </div>
            <div>
              <dt className="text-muted-foreground">当前状态</dt>
              <dd>
                <Badge variant={statusVariants[ticket.status] || "gray"}>
                  {statusLabels[ticket.status] || ticket.status}
                </Badge>
              </dd>
            </div>
            <div>
              <dt className="text-muted-foreground">申请人</dt>
              <dd className="font-medium">
                {ticket.applicant?.name || ticket.applicantId}{" "}
                {ticket.applicant?.deptId && `(${ticket.applicant.deptId})`}
              </dd>
            </div>
            {ticket.targetModel && (
              <div>
                <dt className="text-muted-foreground">目标型号</dt>
                <dd className="font-medium">
                  {ticket.targetModel.brandName} {ticket.targetModel.modelName}
                </dd>
              </div>
            )}
            {ticket.targetAsset && (
              <div>
                <dt className="text-muted-foreground">目标资产</dt>
                <dd className="font-medium">
                  {ticket.targetAsset.model
                    ? `${ticket.targetAsset.model.brandName} ${ticket.targetAsset.model.modelName}`
                    : ticket.targetAsset.id}
                </dd>
              </div>
            )}
            <div>
              <dt className="text-muted-foreground">创建时间</dt>
              <dd className="font-medium">
                {format(new Date(ticket.createdAt), "yyyy-MM-dd HH:mm")}
              </dd>
            </div>
            <div className="col-span-2">
              <dt className="text-muted-foreground">申领理由</dt>
              <dd className="font-medium">{ticket.reason || "—"}</dd>
            </div>
            {ticket.rejectReason && (
              <div className="col-span-2">
                <dt className="text-destructive">驳回原因</dt>
                <dd className="font-medium text-destructive">{ticket.rejectReason}</dd>
              </div>
            )}
          </dl>
        </CardContent>
      </Card>

      {/* Timeline */}
      <Card>
        <CardHeader>
          <CardTitle className="text-base">处理时间轴</CardTitle>
        </CardHeader>
        <CardContent>
          <TicketTimeline events={timeline} />
        </CardContent>
      </Card>

      {/* Actions */}
      {!isTerminal && (
        <div className="space-y-2">
          {actionError && (
            <div className="p-3 rounded-lg bg-destructive/10 text-destructive text-sm">
              {actionError}
            </div>
          )}

          <div className="flex gap-3 justify-end">
            {canCancel && (
              <Button
                variant="outline"
                onClick={handleCancel}
                disabled={actionLoading !== null}
              >
                {actionLoading === "cancel" ? (
                  <Loader2 className="w-4 h-4 mr-1 animate-spin" />
                ) : (
                  <Ban className="w-4 h-4 mr-1" />
                )}
                撤销工单
              </Button>
            )}

            {canApprove && (
              <>
                <Button
                  variant="outline"
                  onClick={handleReject}
                  disabled={actionLoading !== null}
                >
                  {actionLoading === "reject" ? (
                    <Loader2 className="w-4 h-4 mr-1 animate-spin" />
                  ) : (
                    <XCircle className="w-4 h-4 mr-1" />
                  )}
                  驳回
                </Button>
                <Button
                  onClick={handleApprove}
                  disabled={actionLoading !== null}
                >
                  {actionLoading === "approve" ? (
                    <Loader2 className="w-4 h-4 mr-1 animate-spin" />
                  ) : (
                    <CheckCircle2 className="w-4 h-4 mr-1" />
                  )}
                  审批通过
                </Button>
              </>
            )}
          </div>
        </div>
      )}
    </div>
  );
}

"use client";

/**
 * 通知中心 (所有角色)
 * 功能: 从 /api/tickets 获取工单数据并派生通知展示
 * 说明: /api/notifications API 不存在，使用工单数据展示通知
 */

import { useState, useEffect } from "react";
import { Card, CardContent } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import { Skeleton } from "@/components/ui/skeleton";
import EmptyState from "@/components/empty-state";
import { apiFetch } from "@/lib/api-client";
import { Bell, CheckCheck, ChevronRight, AlertTriangle, RefreshCw } from "lucide-react";
import Link from "next/link";
import { format } from "date-fns";

// ---- Types ----

interface TicketItem {
  id: string;
  type: string;
  status: string;
  reason: string;
  createdAt: string;
}

interface PaginatedTickets {
  tickets: TicketItem[];
  pagination: { page: number; limit: number; total: number; totalPages: number };
}

interface NotificationItem {
  id: string;
  type: string;
  title: string;
  body: string;
  read: boolean;
  createdAt: string;
  ticketId?: string;
}

// ---- Labels ----

const statusLabels: Record<string, string> = {
  SUBMITTED: "已提交",
  PENDING_MANAGER_1: "待主管审批",
  PENDING_MANAGER_2: "待主管审批",
  PENDING_IT: "待IT处理",
  APPROVED: "已通过",
  REJECTED: "已驳回",
  IN_PROGRESS: "处理中",
  COMPLETED: "已完成",
  CANCELLED: "已取消",
};

const typeLabels: Record<string, string> = {
  APPLY: "申领",
  RETURN: "归还",
  REPAIR: "报修",
  TRANSFER: "调拨",
};

// ---- Helpers ----

/**
 * Derive notification items from ticket data.
 * Each ticket creates one notification summarizing its current status.
 */
function deriveNotificationsFromTickets(tickets: TicketItem[]): NotificationItem[] {
  return tickets.map((ticket) => {
    const typeLabel = typeLabels[ticket.type] || ticket.type;
    const statusLabel = statusLabels[ticket.status] || ticket.status;

    let title = `${typeLabel}工单更新`;
    let body = `工单 ${ticket.id} 当前状态: ${statusLabel}`;

    if (ticket.status.includes("PENDING")) {
      title = `${typeLabel}审批待处理`;
      body = `你的${typeLabel}工单 ${ticket.id} 正在等待 ${statusLabel}`;
    } else if (ticket.status === "APPROVED") {
      title = `${typeLabel}申请已通过`;
      body = `你申请的${typeLabel}工单 ${ticket.id} 已审批通过`;
    } else if (ticket.status === "REJECTED") {
      title = `${typeLabel}申请被驳回`;
      body = `你的${typeLabel}工单 ${ticket.id} 已被驳回`;
    } else if (ticket.status === "IN_PROGRESS") {
      title = `${typeLabel}工单处理中`;
      body = `你的${typeLabel}工单 ${ticket.id} 正在处理中`;
    } else if (ticket.status === "COMPLETED") {
      title = `${typeLabel}工单已完成`;
      body = `你的${typeLabel}工单 ${ticket.id} 已完成`;
    }

    return {
      id: `ntf-${ticket.id}`,
      type: ticket.type,
      title,
      body,
      read: ["COMPLETED", "CANCELLED"].includes(ticket.status),
      createdAt: ticket.createdAt,
      ticketId: ticket.id,
    };
  });
}

// ---- Component ----

export default function NotificationsPage() {
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState("");
  const [notifications, setNotifications] = useState<NotificationItem[]>(() => {
    // Initialize with empty to avoid hydration mismatch
    return [];
  });

  const fetchNotifications = async () => {
    setLoading(true);
    setError("");
    try {
      // Fetch recent tickets to derive notifications
      const data = await apiFetch<PaginatedTickets>("/api/tickets?limit=20");
      const derived = deriveNotificationsFromTickets(data.tickets || []);
      setNotifications(derived);
    } catch (err: unknown) {
      setError(err instanceof Error ? err.message : "加载通知失败");
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchNotifications();
  }, []);

  const unreadCount = notifications.filter((n) => !n.read).length;

  const markAllAsRead = () => {
    setNotifications((prev) => prev.map((n) => ({ ...n, read: true })));
  };

  const markAsRead = (id: string) => {
    setNotifications((prev) =>
      prev.map((n) => (n.id === id ? { ...n, read: true } : n))
    );
  };

  // ---- Loading ----
  if (loading) {
    return (
      <div className="max-w-3xl mx-auto space-y-6">
        <Skeleton className="h-8 w-48" />
        <div className="space-y-2">
          {Array.from({ length: 5 }).map((_, i) => (
            <Skeleton key={i} className="h-20 rounded-xl" />
          ))}
        </div>
      </div>
    );
  }

  // ---- Error ----
  if (error) {
    return (
      <div className="max-w-3xl mx-auto flex flex-col items-center justify-center py-16 text-center">
        <AlertTriangle className="w-12 h-12 text-destructive mb-4" />
        <h2 className="text-lg font-semibold mb-2">加载失败</h2>
        <p className="text-sm text-muted-foreground mb-4">{error}</p>
        <Button variant="outline" onClick={fetchNotifications}>
          <RefreshCw className="w-4 h-4 mr-2" />
          重试
        </Button>
      </div>
    );
  }

  // ---- Empty ----
  if (notifications.length === 0) {
    return (
      <div className="max-w-3xl mx-auto space-y-6">
        <h1 className="text-2xl font-bold tracking-tight">通知中心</h1>
        <EmptyState
          icon={Bell}
          title="暂无通知"
          description="当你收到审批请求、工单更新等通知时，将显示在这里。"
        />
      </div>
    );
  }

  return (
    <div className="max-w-3xl mx-auto space-y-6">
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-2xl font-bold tracking-tight">通知中心</h1>
          <p className="text-muted-foreground mt-1">
            {unreadCount > 0
              ? `你有 ${unreadCount} 条未读通知`
              : "所有通知已读"}
          </p>
        </div>
        {unreadCount > 0 && (
          <Button variant="outline" size="sm" onClick={markAllAsRead}>
            <CheckCheck className="w-4 h-4 mr-1" />
            全部标已读
          </Button>
        )}
      </div>

      <div className="space-y-2">
        {notifications.map((n) => (
          <Link
            key={n.id}
            href={n.ticketId ? `/tickets/${n.ticketId}` : "#"}
            onClick={() => markAsRead(n.id)}
          >
            <Card
              className={`cursor-pointer transition-colors hover:shadow-sm ${
                !n.read ? "border-l-4 border-l-primary bg-secondary/50" : ""
              }`}
            >
              <CardContent className="p-4 flex items-start justify-between gap-4">
                <div className="flex-1 min-w-0">
                  <div className="flex items-center gap-2 mb-1">
                    <span className="font-medium text-sm">{n.title}</span>
                    {!n.read && <Badge variant="blue">新</Badge>}
                  </div>
                  <p className="text-sm text-muted-foreground line-clamp-2">{n.body}</p>
                  <p className="text-xs text-muted-foreground mt-1">
                    {format(new Date(n.createdAt), "yyyy-MM-dd HH:mm")}
                  </p>
                </div>
                <ChevronRight className="w-4 h-4 text-muted-foreground flex-shrink-0 mt-1" />
              </CardContent>
            </Card>
          </Link>
        ))}
      </div>
    </div>
  );
}

